<span class="line"><span style="color:#CDD6F4;">    client</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Box</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">dyn</span><span style="color:#F9E2AF;font-style:italic;"> LlmClient</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
